```class Solution {
public:
    int minStartingIndex(string s, string pattern) {
        int n = s.length();
        int m = pattern.length();

        vector<vector<int>> dp(n + 1, vector<int>(m + 1));

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                if (s[i - 1] == pattern[j - 1]) {
                    dp[i][j] = j;
                } else {
                    dp[i][j] = min({dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]});
                }
            }
        }

        int result = dp[n][m];
        return result;
    }
};
```

